import{C as t,o as n,c as l,a5 as s,E as o}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"2. TVU — Transaction Validation Unit","description":"","frontmatter":{},"headers":[],"relativePath":"module-6/2-tvu.md","filePath":"module-6/2-tvu.md","lastUpdated":1780937944000}'),r={name:"module-6/2-tvu.md"},k=Object.assign(r,{setup(p){const i={id:"m6-2-tvu",title:"🧠 Mini-check: TVU",intro:"2 питання.",questions:[{type:"mcq",q:"TVU does:",options:["Receives shreds від turbine","Verifies leader's signatures","Replays TXs у block to verify execution","Forwards shreds до next layer turbine"],correct:[0,1,2,3],explanation:'TVU = "validate і replay blocks". Module 6.2.'},{type:"compare",q:"TPU vs TVU?",ideal:`TPU (Transaction Processing Unit): incoming TXs path. Receives client TXs through QUIC, verifies, includes у block if leader, forwards to leader if not. Active when validator producing blocks.

TVU (Transaction Validation Unit): incoming blocks path. Receives shreds from turbine (broadcasts of other leaders' blocks), verifies, replays TXs to check leader didn't lie, votes. Active when validator validating others' blocks (most of the time).

Most validators spend majority of time у TVU (only leader ~25% of slots, most time validating). Both run concurrently.`,explanation:"Module 6.1, 6.2."}]};return(h,a)=>{const e=t("Quiz");return n(),l("div",null,[a[0]||(a[0]=s(`<h1 id="_2-tvu-—-transaction-validation-unit" tabindex="-1">2. TVU — Transaction Validation Unit <a class="header-anchor" href="#_2-tvu-—-transaction-validation-unit" aria-label="Permalink to &quot;2. TVU — Transaction Validation Unit&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>TVU</strong> (Transaction Validation Unit) — частина validator що receives shreds від turbine (other leaders&#39; blocks), reconstructs blocks, replays TXs to verify execution, votes за block.</p><p>Most validator time spent у TVU (validating others) — only ~25% slots own leader (TPU active).</p><h2 id="концепти" tabindex="-1">Концепти <a class="header-anchor" href="#концепти" aria-label="Permalink to &quot;Концепти&quot;">​</a></h2><h3 id="tvu-pipeline" tabindex="-1">TVU pipeline <a class="header-anchor" href="#tvu-pipeline" aria-label="Permalink to &quot;TVU pipeline&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Shreds received via turbine</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>Shred validation (signatures, format)</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>Block reconstruction (when enough shreds)</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>Bank replay (execute TXs)</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>Bank verification (compare local hash to leader&#39;s)</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>Vote signing → submit through TPU</span></span></code></pre></div><h3 id="replay-stage" tabindex="-1">Replay stage <a class="header-anchor" href="#replay-stage" aria-label="Permalink to &quot;Replay stage&quot;">​</a></h3><p>Validator <strong>replays</strong> TXs у block — executes them locally, computes resulting state. Compares result hash to leader&#39;s claimed hash.</p><p>If matches → leader didn&#39;t lie → vote. If differs → leader malicious / buggy → don&#39;t vote, raise alarm.</p><p>Це security mechanism: every validator independently verifies every block. Leader can&#39;t include invalid TXs (would be caught).</p><h3 id="tpu-vs-tvu-concurrency" tabindex="-1">TPU vs TVU concurrency <a class="header-anchor" href="#tpu-vs-tvu-concurrency" aria-label="Permalink to &quot;TPU vs TVU concurrency&quot;">​</a></h3><p>Both run continuously у validator process:</p><ul><li>TPU: receive + process incoming TXs (more active when leader)</li><li>TVU: receive + validate incoming blocks (active most of the time)</li></ul><p>Different threads/cores. Don&#39;t compete for resources.</p><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><p>Replay performance critical для voting on time:</p><ul><li>Slow replay → vote late → miss credits</li><li>Cause: slow CPU, slow accountsDB (disk I/O)</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> solana</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -iE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;replay|tvu&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -10</span></span></code></pre></div><p>Look для:</p><ul><li>&quot;Replay slot X took N ms&quot; — long times = bottleneck</li><li>&quot;Replay stage stalled&quot; — serious issue</li></ul><h2 id="hands-on" tabindex="-1">Hands-on <a class="header-anchor" href="#hands-on" aria-label="Permalink to &quot;Hands-on&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Replay activity</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> solana</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> replay</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -10</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Disk I/O (replay reads/writes accountsDB)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iostat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -30</span></span></code></pre></div><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,24)),o(e,{data:i}),a[1]||(a[1]=s('<h2 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h2><p><a href="/glossary#t"><code>TVU</code></a>, <a href="/glossary#r"><code>Replay stage</code></a>, <a href="/glossary#b"><code>Block verification</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://docs.anza.xyz/validator/tvu" target="_blank" rel="noreferrer">Anza: TVU</a></li></ul><hr><p><strong>Попередньо:</strong> <a href="/module-6/1-tpu">← 1. TPU</a> | <strong>Наступне:</strong> <a href="/module-6/3-accountsdb">3. AccountsDB →</a></p>',6))])}}});export{c as __pageData,k as default};
